    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #27242c;
}

