    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: #c7dff0;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
