@page "/chat"
@rendermode InteractiveServer
@using sv_43782fa80bcb49b2bbe0dfeecb5c3310.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <main class="message-area @(threadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => hoveredMessageId = null">
                        <div class="message-content-wrapper">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-text">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-bar">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{
                                var summary = threadSummaries.GetValueOrDefault(msg.Id);
                            }
                            @if (summary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }
                        </div>

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg)">
                                    💬 Reply
                                </button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">
                                        😀 React
                                    </button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option"
                                                        @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                    @emoji
                                                </button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMessageKeyDownAsync"
                          placeholder="Message #@activeChannel.Name" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ── Right Panel: Thread View ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <span class="author">@threadRootMessage.Author</span>
                    <span class="timestamp">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                </div>
                <div class="message-text">@threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (isLoadingThread)
                {
                    <div class="loading-indicator">Loading thread…</div>
                }
                else
                {
                    @foreach (var reply in threadReplies)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-text">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-bar">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="thread-input-area">
                <textarea @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDownAsync"
                          placeholder="Reply…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<Message> threadReplies = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private string newMessageText = "";
    private string threadReplyText = "";

    private bool threadOpen;
    private Message? threadRootMessage;
    private bool isLoadingThread;
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    private ElementReference messageListRef;

    private const int PageSize = 30;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (activeChannelId == channel.Id) return;

        activeChannel = channel;
        activeChannelId = channel.Id;
        messages.Clear();
        threadSummaries.Clear();
        hasMoreMessages = true;
        emojiPickerMessageId = null;

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        await BuildThreadSummariesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    private async Task BuildThreadSummariesAsync()
    {
        threadSummaries.Clear();

        // Identify root messages (those that have replies pointing to them)
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replyToIds = messages
            .Where(m => m.ReplyToId.HasValue)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        foreach (var rootId in replyToIds.Where(rootIds.Contains))
        {
            var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, replies.Count, replies.Max(r => r.SentAt));
            }
        }

        // Also check via GetThreadAsync for root messages that may have replies not loaded in the current page
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadSummaries.ContainsKey(m.Id)))
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 0)
                {
                    threadSummaries[msg.Id] = new ThreadSummary(msg.Id, thread.Count, thread.Max(t => t.SentAt));
                }
            }
            catch
            {
                // Thread may not exist; ignore
            }
        }
    }

    private async Task HandleScrollAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;
        isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;

        messages.InsertRange(0, older);
        await BuildThreadSummariesAsync();

        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task HandleMessageKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadOpen = true;
        isLoadingThread = true;
        threadReplyText = "";
        emojiPickerMessageId = null;

        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        isLoadingThread = false;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        threadReplyText = "";

        // Update thread summary in main view
        var count = threadReplies.Count;
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, count, reply.SentAt);
    }

    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
            messages = refreshed;
        }

        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval", "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length <= 40 ? description : description[..37] + "…";
    }
}

