+
+        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
+        if (scrollTop < 50)
+        {
+            await LoadOlderMessagesAsync();
+        }
+    }
+
+    private async Task LoadOlderMessagesAsync()
+    {
+        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;
+        isLoadingMore = true;
+
+        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
+        if (older.Count < PageSize) hasMoreMessages = false;
+
+        messages.InsertRange(0, older);
+        await BuildThreadSummariesAsync();
+
+        isLoadingMore = false;
+    }
+
+    private async Task SendMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;
+
+        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
+        messages.Add(sent);
+        newMessageText = "";
+
+        await ScrollToBottomAsync();
+    }
+
+    private async Task HandleMessageKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendMessageAsync();
+        }
+    }
+
+    private async Task OpenThreadAsync(Message rootMessage)
+    {
+        threadRootMessage = rootMessage;
+        threadOpen = true;
+        isLoadingThread = true;
+        threadReplyText = "";
+        emojiPickerMessageId = null;
+
+        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
+        isLoadingThread = false;
+    }
+
+    private void CloseThread()
+    {
+        threadOpen = false;
+        threadRootMessage = null;
+        threadReplies.Clear();
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
+        threadReplies.Add(reply);
+        threadReplyText = "";
+
+        // Update thread summary in main view
+        var count = threadReplies.Count;
+        threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, count, reply.SentAt);
+    }
+
+    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    private async Task AddReactionAsync(int messageId, string emoji)
+    {
+        emojiPickerMessageId = null;
+        await ChatService.AddReactionAsync(messageId, emoji);
+
+        // Refresh messages to show updated reactions
+        if (activeChannel is not null)
+        {
+            var refreshed = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
+            messages = refreshed;
+        }
+
+        if (threadRootMessage is not null)
+        {
+            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
+        }
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private async Task ScrollToBottomAsync()
+    {
+        await Task.Yield();
+        await JS.InvokeVoidAsync("eval", "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+
+        return diff.TotalSeconds switch
+        {
+            < 60 => "just now",
+            < 3600 => $"{(int)diff.TotalMinutes} min ago",
+            < 86400 => $"{(int)diff.TotalHours}h ago",
+            < 604800 => $"{(int)diff.TotalDays}d ago",
+            _ => sentAt.ToString("MMM d, yyyy")
+        };
+    }
+
+    private static string TruncateDescription(string description)
+    {
+        return description.Length <= 40 ? description : description[..37] + "…";
+    }
+}
